
import React from 'react';
import { useRouter } from 'next/router';

export default function Layout({ children }) {
  const router = useRouter();
  const navLinks = [
    { href: '/', label: 'Dashboard' },
    { href: '/books', label: 'Catalog' },
    { href: '/aisles', label: 'Aisles & Shelves' },
  ];
  return (
    <div className="min-h-screen bg-[#f9fafb] text-gray-900">
      {/* Top Navigation Bar */}
      <header className="w-full bg-white border-b border-gray-200 px-6 py-3 flex items-center justify-between sticky top-0 z-30">
        <div className="flex items-center gap-3">
          <span className="inline-flex items-center gap-2 font-extrabold text-2xl tracking-tight text-green-900">
            <svg width="32" height="32" fill="none" viewBox="0 0 32 32" aria-hidden="true">
              <rect x="4" y="8" width="24" height="16" rx="4" fill="#276749"/>
              <rect x="8" y="12" width="16" height="8" rx="2" fill="#fff"/>
            </svg>
            LibraTrack
          </span>
        </div>
        <nav className="flex gap-2 md:gap-4 items-center">
          {navLinks.map(link => (
            <a
              key={link.href}
              href={link.href}
              className={`px-3 py-2 rounded font-semibold text-green-900 hover:bg-green-50 focus:outline-none focus:ring-2 focus:ring-green-700 focus:bg-green-50 transition${router.pathname === link.href ? ' bg-green-100' : ''}`}
              aria-current={router.pathname === link.href ? 'page' : undefined}
            >
              {link.label}
            </a>
          ))}
        </nav>
        <a href="/login" className="ml-4 px-4 py-2 bg-green-800 text-white rounded-lg font-semibold shadow hover:bg-green-900 focus:outline-none focus:ring-2 focus:ring-green-700 transition">Sign In</a>
      </header>
      <main className="max-w-7xl mx-auto w-full px-4 py-8">
        {children}
      </main>
    </div>
  );
}
